fields.collector:
$warningEventIds = 8003, 8006, 8021, 8024, 8028, 8038
$blockEventIds   = 8004, 8007, 8021, 8024, 8029, 8040
$allEventIds     = $warningEventIds + $blockEventIds | Sort-Object -Unique
$startTime       = (Get-Date).AddHours(-24)

# AppLocker stores file paths with macros (%OSDRIVE% %WINDIR% %SYSTEM32%
# %PROGRAMFILES%). Expand them all so Test-Path / version / hash resolve;
# without this only %OSDRIVE% / already-absolute paths survive and every
# %SYSTEM32%\*.dll audit event is silently dropped. Falls back to the
# 32-bit locations (SysWOW64, Program Files (x86)) when the native path
# does not exist.
$expandMacroPath = {
    param($RawPath)
    if ([string]::IsNullOrEmpty($RawPath)) { return $RawPath }
    $resolvedPath = $RawPath.Replace('%OSDRIVE%', $env:SystemDrive).Replace('%WINDIR%', $env:windir).Replace('%SYSTEM32%', "$env:windir\System32").Replace('%PROGRAMFILES%', $env:ProgramFiles)
    if (-not (Test-Path $resolvedPath -ErrorAction SilentlyContinue)) {
        $fallbackPath = $RawPath.Replace('%OSDRIVE%', $env:SystemDrive).Replace('%WINDIR%', $env:windir).Replace('%SYSTEM32%', "$env:windir\SysWOW64").Replace('%PROGRAMFILES%', ${env:ProgramFiles(x86)})
        if (Test-Path $fallbackPath -ErrorAction SilentlyContinue) { $resolvedPath = $fallbackPath }
    }
    $resolvedPath
}

# Incremental: persist a per-channel EventRecordId watermark so frequent (e.g.
# hourly) runs ship only NEW events. Committed by the host only after upload.
$stateDir   = Join-Path $env:ProgramData 'LogIngestionPortal'
$stateFile  = Join-Path $stateDir 'AppLockerWatermark.json'
$watermarks = @{}
if (Test-Path $stateFile) {
    try { (Get-Content $stateFile -Raw | ConvertFrom-Json).PSObject.Properties | ForEach-Object { $watermarks[$_.Name] = [long]$_.Value } } catch { $watermarks = @{} }
}
$newWatermarks = @{}

$logSources = @(
    @{ LogName = 'Microsoft-Windows-AppLocker/EXE and DLL'; RuleType = 'Application' }
    @{ LogName = 'Microsoft-Windows-AppLocker/MSI and Script'; RuleType = 'Script' }
)

$rawEvents = foreach ($logSource in $logSources) {
    $lastRecordId  = [long]$watermarks[$logSource.LogName]
    $channelEvents = Get-WinEvent -FilterHashtable @{ LogName = $logSource.LogName; Id = $allEventIds; StartTime = $startTime } -ErrorAction SilentlyContinue
    # Channel cleared/wrapped (newest RecordId fell below the watermark): start over.
    $channelMax = ($channelEvents | Measure-Object -Property RecordId -Maximum).Maximum
    if ($null -ne $channelMax -and $channelMax -lt $lastRecordId) { $lastRecordId = 0 }
    # Advance to the newest event seen (even ones skipped below) so they are not re-read.
    $newWatermarks[$logSource.LogName] = if ($null -ne $channelMax -and [long]$channelMax -gt $lastRecordId) { [long]$channelMax } else { $lastRecordId }
    foreach ($winEvent in $channelEvents) {
        if ([long]$winEvent.RecordId -le $lastRecordId) { continue }
        $ruleData = ([xml]$winEvent.ToXml()).Event.UserData.RuleAndFileData
        $rawPath  = [string]$ruleData.FilePath
        $filePath = & $expandMacroPath $rawPath
        [pscustomobject]@{
            WinEvent = $winEvent
            RuleType = $logSource.RuleType
            RuleData = $ruleData
            RawPath  = $rawPath
            FilePath = $filePath
        }
    }
}

# Count how many raw events reference each path (the file's use count),
# before de-duplicating by event record id below.
$pathUseCount = @{}
foreach ($rawEvent in $rawEvents) {
    if ($rawEvent.RawPath) { $pathUseCount[$rawEvent.RawPath] = [int]$pathUseCount[$rawEvent.RawPath] + 1 }
}

$events = foreach ($rawEvent in ($rawEvents | Sort-Object { $_.WinEvent.RecordId } -Unique)) {
    $winEvent = $rawEvent.WinEvent
    $ruleData = $rawEvent.RuleData
    $filePath = $rawEvent.FilePath
    $fileName = if ($filePath) { Split-Path -Leaf $filePath }

    if ([string]::IsNullOrEmpty($filePath) -or $filePath -match 'PSSCRIPTPOLICYTEST' -or -not (Test-Path $filePath -ErrorAction SilentlyContinue)) { continue }

    $versionInfo     = (Get-ItemProperty $filePath -ErrorAction SilentlyContinue).VersionInfo
    $fileDescription = if ($versionInfo.FileDescription) { $versionInfo.FileDescription } else { $fileName }
    $productName     = if ($versionInfo.ProductName) { $versionInfo.ProductName } else { $fileDescription }
    $fileVersion     = if ($versionInfo.FileVersion) { $versionInfo.FileVersion } else { 'Unavailable' }
    try { $fileHash = (Get-FileHash $filePath -Algorithm SHA256 -ErrorAction Stop).Hash } catch { $fileHash = 'Access denied' }
    $fileLength = (Get-Item $filePath -ErrorAction SilentlyContinue).Length

    $appLockerInfo = Get-AppLockerFileInformation $filePath -ErrorAction SilentlyContinue
    $publisherName = $appLockerInfo.Publisher.PublisherName
    if ([string]::IsNullOrEmpty($publisherName)) {
        $publisher = 'Unsigned'; $fullPublisher = 'N/A'; $signed = 'No'
    }
    else {
        $publisher = (($publisherName -split ',')[0]).TrimStart('O='); $fullPublisher = [string]$appLockerInfo.Publisher; $signed = 'Yes'
    }

    if ($signed -eq 'Yes' -and $productName -ne $fileDescription) {
        try { $publisherRule = [string]($appLockerInfo | New-AppLockerPolicy -RuleType Publisher -User Everyone -RuleNamePrefix $productName -Xml -ErrorAction Stop) } catch { $publisherRule = 'Unsigned Application' }
    }
    else { $publisherRule = 'Unsigned Application' }
    try { $hashRule = [string]($appLockerInfo | New-AppLockerPolicy -RuleType Hash -User Everyone -RuleNamePrefix $productName -Xml -ErrorAction Stop) } catch { $hashRule = $null }
    try { $pathRule = [string]($appLockerInfo | New-AppLockerPolicy -RuleType Path -User Everyone -RuleNamePrefix $productName -Xml -ErrorAction Stop) } catch { $pathRule = $null }

    $fullyQualifiedBinaryName = [string]$ruleData.Fqbn
    $fqbn = $null
    if ($fullyQualifiedBinaryName) {
        $fqbnParts = $fullyQualifiedBinaryName -split '\\'
        $fqbn = [pscustomobject]@{ PublisherDN = $fqbnParts[0]; ProductName = $fqbnParts[1]; BinaryName = $fqbnParts[2]; Version = $fqbnParts[3] }
    }

    [pscustomobject]@{
        EventRecordId          = [long]$winEvent.RecordId
        EventTime              = $winEvent.TimeCreated.ToUniversalTime().ToString('o')
        EventType              = if ($blockEventIds -contains $winEvent.Id) { 'Denied' } else { 'Audited' }
        EventId                = [int]$winEvent.Id
        EventMessage           = $winEvent.Message
        RuleType               = $rawEvent.RuleType
        PolicyName             = [string]$ruleData.PolicyName
        RuleName               = [string]$ruleData.RuleName
        TargetUser             = [string]$ruleData.TargetUser
        FileDescription        = $fileDescription
        FileVersion            = $fileVersion
        ProductName            = $productName
        FileHash               = $fileHash
        FileName               = $fileName
        FilePath               = $filePath
        FileLength             = $fileLength
        Publisher              = $publisher
        FullPublisher          = $fullPublisher
        Fqbn                   = $fqbn
        FileUseCount           = [int]$pathUseCount[$rawEvent.RawPath]
        AppLockerPublisherRule = $publisherRule
        AppLockerHashRule      = $hashRule
        AppLockerPathRule      = $pathRule
        Signed                 = $signed
    }
}
$result = @($events)
# Queue the watermark to be written host-side only after a successful upload
# (collectors are read-only). Guarded so standalone/-PreviewData runs still work.
if ($script:PendingState) {
    try { $script:PendingState.Add([pscustomobject]@{ Path = $stateFile; Json = ($newWatermarks | ConvertTo-Json -Compress) }) } catch { }
}
$result
